//! Sovereign math / logic / probability evaluation for the shell.
//!
//! Moonshine is a shell: an unknown line is normally spawned as an external
//! command, so typing `1+2` used to die with `Failed to spawn 1+2`. This
//! module gives the shell a calculator: before that error path, a line that is
//! plainly an arithmetic expression is evaluated, and the explicit `math` /
//! `logic` / `prob` verbs route to the same sovereign runtime.
//!
//! Nothing here re-implements arithmetic. Every result is computed by the
//! gnosis `monster`/`gnexec` evaluator (the sovereign TypeScript runtime) by
//! generating a tiny `export function __eval()` and reading its value back.
//! `prob` calls the real `buleyeanWeights` God Formula from `@a0n/aeon-logic`;
//! `logic` enumerates a truth table in the same runtime.

use anyhow::{anyhow, Result};
use std::path::PathBuf;
use std::process::Command;
use std::sync::atomic::{AtomicUsize, Ordering};

static EVAL_SEQ: AtomicUsize = AtomicUsize::new(0);

/// Identifiers allowed to appear in an auto-detected arithmetic line without
/// disqualifying it as a command. Kept tiny so we never shadow real binaries.
const ARITH_ALLOWED_IDENTS: &[&str] = &["Math", "true", "false", "NaN", "Infinity"];

/// Locate the sovereign `monster`/`gnexec` evaluator binary.
///
/// Order: `MOONSHINE_MONSTER_BIN` env override, then the sibling polyglot
/// crate's build output (`../polyglot/target/{release,debug}/{monster,gnexec}`),
/// then `gnexec`/`monster` on `PATH`, then the bare name.
fn locate_monster() -> PathBuf {
    if let Ok(explicit) = std::env::var("MOONSHINE_MONSTER_BIN") {
        let trimmed = explicit.trim();
        if !trimmed.is_empty() {
            return PathBuf::from(trimmed);
        }
    }

    let mut roots: Vec<PathBuf> = vec![PathBuf::from(env!("CARGO_MANIFEST_DIR"))];
    if let Ok(cwd) = std::env::current_dir() {
        roots.push(cwd);
    }
    for root in &roots {
        for profile in ["release", "debug"] {
            for bin in ["monster", "gnexec"] {
                let cand = root
                    .join("..")
                    .join("polyglot")
                    .join("target")
                    .join(profile)
                    .join(bin);
                if cand.exists() {
                    return cand;
                }
            }
        }
    }

    for bin in ["gnexec", "monster"] {
        if let Ok(on_path) = which::which(bin) {
            return on_path;
        }
    }

    PathBuf::from("gnexec")
}

/// Locate `open-source/aeon-logic/src/buleyean.ts` (the canonical God Formula)
/// so `prob` calls the real package rather than a copy. `MOONSHINE_AEON_LOGIC`
/// overrides the file path. Otherwise we walk upward from the crate dir, the
/// CWD, and the executable's dir looking for the monorepo-relative path.
fn aeon_logic_buleyean() -> Option<PathBuf> {
    if let Ok(explicit) = std::env::var("MOONSHINE_AEON_LOGIC") {
        let pb = PathBuf::from(explicit.trim());
        if pb.exists() {
            return Some(pb);
        }
    }

    let rel = ["open-source", "aeon-logic", "src", "buleyean.ts"];
    let mut starts: Vec<PathBuf> = vec![PathBuf::from(env!("CARGO_MANIFEST_DIR"))];
    if let Ok(cwd) = std::env::current_dir() {
        starts.push(cwd);
    }
    if let Ok(exe) = std::env::current_exe() {
        if let Some(dir) = exe.parent() {
            starts.push(dir.to_path_buf());
        }
    }

    for start in starts {
        let mut cur = start;
        loop {
            let mut cand = cur.clone();
            for seg in rel {
                cand = cand.join(seg);
            }
            if cand.exists() {
                return Some(cand);
            }
            match cur.parent() {
                Some(parent) => cur = parent.to_path_buf(),
                None => break,
            }
        }
    }
    None
}

/// Locate an arbitrary `open-source/aeon-logic/src/<file>` by walking up from the
/// crate / cwd / exe dir, mirroring [`aeon_logic_buleyean`]. Honors the
/// `MOONSHINE_AEON_LOGIC` override by treating its parent dir as the src root.
fn aeon_logic_src(file: &str) -> Option<PathBuf> {
    if let Ok(explicit) = std::env::var("MOONSHINE_AEON_LOGIC") {
        let base = PathBuf::from(explicit.trim());
        let dir = if base.is_dir() { base } else { base.parent()?.to_path_buf() };
        let cand = dir.join(file);
        if cand.exists() {
            return Some(cand);
        }
    }
    let rel = ["open-source", "aeon-logic", "src", file];
    let mut starts: Vec<PathBuf> = vec![PathBuf::from(env!("CARGO_MANIFEST_DIR"))];
    if let Ok(cwd) = std::env::current_dir() {
        starts.push(cwd);
    }
    if let Ok(exe) = std::env::current_exe() {
        if let Some(dir) = exe.parent() {
            starts.push(dir.to_path_buf());
        }
    }
    for start in starts {
        let mut cur = start;
        loop {
            let mut cand = cur.clone();
            for seg in rel {
                cand = cand.join(seg);
            }
            if cand.exists() {
                return Some(cand);
            }
            match cur.parent() {
                Some(parent) => cur = parent.to_path_buf(),
                None => break,
            }
        }
    }
    None
}

fn temp_ts_path() -> PathBuf {
    let seq = EVAL_SEQ.fetch_add(1, Ordering::Relaxed);
    std::env::temp_dir().join(format!("moonshine-eval-{}-{}.ts", std::process::id(), seq))
}

/// Write `ts_source` to a temp file, run `monster <file> --export __eval`, and
/// return the trimmed stdout (the value of `__eval`). `multi_file` enables
/// gnexec's relative-import resolution (needed when the program imports
/// aeon-logic).
fn run_export(ts_source: &str, multi_file: bool) -> Result<String> {
    let bin = locate_monster();
    let path = temp_ts_path();
    std::fs::write(&path, ts_source).map_err(|e| anyhow!("failed to stage eval program: {e}"))?;

    let mut cmd = Command::new(&bin);
    cmd.arg(&path).arg("--export").arg("__eval");
    if multi_file {
        cmd.env("GNEXEC_MULTI_FILE", "1");
    }
    let result = cmd.output();
    let _ = std::fs::remove_file(&path);

    let output = result.map_err(|e| {
        anyhow!(
            "could not launch the sovereign evaluator at {} ({}). Build it with \
             `monster-build` / cargo build in open-source/gnosis/polyglot, or set \
             MOONSHINE_MONSTER_BIN.",
            bin.display(),
            e
        )
    })?;

    if !output.status.success() {
        let stderr = String::from_utf8_lossy(&output.stderr);
        let detail = stderr
            .lines()
            .map(|l| l.trim())
            .rfind(|l| !l.is_empty() && !l.starts_with("[gnexec]"))
            .map(|l| l.trim_start_matches("monster:").trim().to_string())
            .filter(|l| !l.is_empty())
            .unwrap_or_else(|| format!("evaluator exited with {}", output.status));
        return Err(anyhow!("{}", detail));
    }

    Ok(String::from_utf8_lossy(&output.stdout).trim().to_string())
}

/// Locate `open-source/gnosis/bin/gnode.js` (the real-Node TS runner) by walking
/// up from the crate / cwd / exe dir. Honors `MOONSHINE_GNODE` override.
fn locate_gnode() -> Option<PathBuf> {
    if let Ok(explicit) = std::env::var("MOONSHINE_GNODE") {
        let pb = PathBuf::from(explicit.trim());
        if pb.exists() {
            return Some(pb);
        }
    }
    let rel = ["open-source", "gnosis", "bin", "gnode.js"];
    let mut starts: Vec<PathBuf> = vec![PathBuf::from(env!("CARGO_MANIFEST_DIR"))];
    if let Ok(cwd) = std::env::current_dir() {
        starts.push(cwd);
    }
    if let Ok(exe) = std::env::current_exe() {
        if let Some(dir) = exe.parent() {
            starts.push(dir.to_path_buf());
        }
    }
    for start in starts {
        let mut cur = start;
        loop {
            let mut cand = cur.clone();
            for seg in rel {
                cand = cand.join(seg);
            }
            if cand.exists() {
                return Some(cand);
            }
            match cur.parent() {
                Some(parent) => cur = parent.to_path_buf(),
                None => break,
            }
        }
    }
    None
}

/// Sentinel framing the result line so we can pick it out of gnode's banner noise.
const GNODE_SENTINEL: &str = "__MOON_RESULT__";

/// Run a self-contained TS program through gnode (a real Node engine — full JS:
/// ES classes, regex, BigInt). The program must `console.log(GNODE_SENTINEL + …)`
/// exactly once; we return the framed text. Used for solvers that gnexec's
/// structural-compute runtime cannot execute (omega, ring).
fn run_via_gnode(ts_source: &str) -> Result<String> {
    let gnode = locate_gnode()
        .ok_or_else(|| anyhow!("could not locate open-source/gnosis/bin/gnode.js (set MOONSHINE_GNODE)"))?;
    let node = std::env::var("MOONSHINE_NODE_BIN").unwrap_or_else(|_| "node".to_string());
    let path = temp_ts_path();
    std::fs::write(&path, ts_source).map_err(|e| anyhow!("failed to stage solver program: {e}"))?;

    let result = Command::new(&node)
        .arg(&gnode)
        .arg("run")
        .arg(&path)
        .output();
    let _ = std::fs::remove_file(&path);

    let output = result.map_err(|e| anyhow!("could not launch node ({node}): {e}"))?;
    let stdout = String::from_utf8_lossy(&output.stdout);
    if let Some(line) = stdout.lines().rev().find(|l| l.contains(GNODE_SENTINEL)) {
        let idx = line.find(GNODE_SENTINEL).unwrap() + GNODE_SENTINEL.len();
        return Ok(line[idx..].trim().to_string());
    }
    let stderr = String::from_utf8_lossy(&output.stderr);
    let detail = stderr
        .lines()
        .map(|l| l.trim())
        .rfind(|l| !l.is_empty() && !l.contains("initSync") && !l.contains("gnode run fallback"))
        .unwrap_or("solver produced no output");
    Err(anyhow!("{}", detail))
}

/// Calculator semantics: a lone trailing `=` is "equals", and `^` means power.
fn normalize_calculator(expr: &str) -> String {
    let mut s = expr.trim().to_string();
    if s.ends_with('=')
        && !s.ends_with("==")
        && !s.ends_with("!=")
        && !s.ends_with("<=")
        && !s.ends_with(">=")
    {
        s.pop();
        s = s.trim_end().to_string();
    }
    // `^` is power for a calculator, not XOR.
    s.replace('^', "**")
}

/// If `line` is plainly a self-contained arithmetic / relational expression
/// (calculator input), return the JS expression to evaluate. Conservative by
/// design: it requires a digit and an operator and rejects any identifier
/// outside [`ARITH_ALLOWED_IDENTS`], so it never swallows a real command like
/// `ls`, `git log`, or `./build.sh`.
pub fn detect_arithmetic(line: &str) -> Option<String> {
    let expr = normalize_calculator(line);
    if expr.is_empty() {
        return None;
    }

    let mut has_digit = false;
    let mut has_operator = false;
    let bytes = expr.as_bytes();
    let mut i = 0;
    while i < bytes.len() {
        let c = bytes[i] as char;
        if c.is_ascii_digit() {
            has_digit = true;
            i += 1;
        } else if c.is_ascii_alphabetic() || c == '_' || c == '$' {
            // Read a full identifier and check the allowlist.
            let start = i;
            while i < bytes.len() {
                let d = bytes[i] as char;
                if d.is_ascii_alphanumeric() || d == '_' || d == '$' {
                    i += 1;
                } else {
                    break;
                }
            }
            let ident = &expr[start..i];
            // A member name (`Math.sqrt`, `Math.PI`) is fine; otherwise the
            // identifier must be on the small allowlist or this isn't a
            // calculator line.
            let is_member = start > 0 && bytes[start - 1] == b'.';
            if !is_member && !ARITH_ALLOWED_IDENTS.contains(&ident) {
                return None;
            }
        } else if matches!(
            c,
            '+' | '-' | '*' | '/' | '%' | '<' | '>' | '=' | '!' | '&' | '|' | '~'
        ) {
            has_operator = true;
            i += 1;
        } else if matches!(c, '(' | ')' | '.' | ',' | ' ' | '\t') {
            i += 1;
        } else {
            return None;
        }
    }

    if has_digit && has_operator {
        Some(expr)
    } else {
        None
    }
}

/// Evaluate an arithmetic / relational expression through the sovereign
/// runtime. `expr` is calculator-normalized first (trailing `=`, `^` power).
pub fn eval_arithmetic(expr: &str) -> Result<String> {
    let cleaned = normalize_calculator(expr);
    if cleaned.is_empty() {
        return Err(anyhow!("nothing to evaluate"));
    }
    let program = format!("export function __eval() {{\n  return ({cleaned});\n}}\n");
    let value = run_export(&program, false)?;
    if value.is_empty() {
        Err(anyhow!("expression produced no value"))
    } else {
        Ok(value)
    }
}

/// Compute the Buleyean view of the given rejection counts using the real
/// `@a0n/aeon-logic` functions, evaluated in the sovereign runtime: the
/// distribution (`buleyeanDistribution`, the compass — God Formula
/// `w_i = T - v_i + 1` normalized) plus the altimeter (`buleDeficit` /
/// `isConverged` — the Bule number `max-min` and whether it reached ground
/// state). This is the `@a0n/maybe` "two numbers" story over one call.
pub fn eval_prob(args: &str) -> Result<String> {
    let counts: Vec<f64> = args
        .split([' ', '\t', ',', ';'])
        .filter(|t| !t.is_empty())
        .map(|t| t.parse::<f64>())
        .collect::<std::result::Result<_, _>>()
        .map_err(|_| anyhow!("usage: prob <rejection-count> [count ...]  (numbers only)"))?;
    if counts.is_empty() {
        return Err(anyhow!("usage: prob <rejection-count> [count ...]"));
    }

    let buleyean = aeon_logic_buleyean().ok_or_else(|| {
        anyhow!(
            "could not locate open-source/aeon-logic/src/buleyean.ts \
             (set MOONSHINE_AEON_LOGIC to its path)"
        )
    })?;

    let counts_js = counts
        .iter()
        .map(|c| format!("{c}"))
        .collect::<Vec<_>>()
        .join(", ");

    let program = format!(
        "import {{ voidBoundary, buleyeanDistribution, buleDeficit, isConverged }} from {import_path:?};\n\
         export function __eval() {{\n\
         \x20 const b = voidBoundary([{counts_js}]);\n\
         \x20 const d = buleyeanDistribution(b);\n\
         \x20 const deficit = buleDeficit(b);\n\
         \x20 let bule = 0;\n\
         \x20 for (let i = 0; i < deficit.length; i++) {{ if (deficit[i] > bule) bule = deficit[i]; }}\n\
         \x20 return {{ probabilities: d.probabilities, weights: d.weights, bule: bule, deficit: deficit, converged: isConverged(b) }};\n\
         }}\n",
        import_path = buleyean.to_string_lossy(),
    );

    let value = run_export(&program, true)?;
    if value.is_empty() {
        Err(anyhow!("aeon-logic returned no distribution"))
    } else {
        Ok(value)
    }
}

/// Evaluate a propositional formula by enumerating its truth table in the
/// sovereign runtime. Supports JS boolean operators (`&& || ! == != < >`),
/// the word forms `and` / `or` / `not`, and the helper functions `imp(a,b)`
/// (implies), `iff(a,b)`, and `xor(a,b)`. Free identifiers become boolean
/// variables. Returns tautology / contradiction / satisfiability and the
/// model count.
pub fn eval_logic(formula: &str) -> Result<String> {
    let trimmed = formula.trim();
    if trimmed.is_empty() {
        return Err(anyhow!("usage: logic <propositional formula>"));
    }

    let translated = translate_logic_words(trimmed);
    let vars = extract_logic_vars(&translated);
    if vars.len() > 16 {
        return Err(anyhow!(
            "logic: {} variables is too many for a truth table (max 16)",
            vars.len()
        ));
    }

    let params = vars.join(", ");
    let mut assigns = String::new();
    for (idx, v) in vars.iter().enumerate() {
        assigns.push_str(&format!(
            "    const {v} = ((__moon_mask >> {idx}) & 1) === 1;\n"
        ));
    }
    let call_args = vars.join(", ");
    let n = vars.len();

    let program = format!(
        "function imp(a, b) {{ return (!a) || b; }}\n\
         function iff(a, b) {{ return a === b; }}\n\
         function xor(a, b) {{ return a !== b; }}\n\
         function __moon_f({params}) {{ return ({translated}); }}\n\
         export function __eval() {{\n\
         \x20 const __moon_n = {n};\n\
         \x20 let __moon_all = true; let __moon_any = false;\n\
         \x20 let __moon_models = 0; let __moon_total = 0;\n\
         \x20 for (let __moon_mask = 0; __moon_mask < (1 << __moon_n); __moon_mask++) {{\n\
         {assigns}\
         \x20\x20\x20 const __moon_r = __moon_f({call_args});\n\
         \x20\x20\x20 __moon_total = __moon_total + 1;\n\
         \x20\x20\x20 if (__moon_r) {{ __moon_any = true; __moon_models = __moon_models + 1; }} else {{ __moon_all = false; }}\n\
         \x20 }}\n\
         \x20 return {{ tautology: __moon_all, contradiction: !__moon_any, satisfiable: __moon_any, models: __moon_models, rows: __moon_total }};\n\
         }}\n",
    );

    let value = run_export(&program, false)?;
    if value.is_empty() {
        Err(anyhow!("could not evaluate formula (check operators)"))
    } else {
        Ok(value)
    }
}

/// Replace whole-word logic aliases (`and`/`or`/`not`) and a few unicode
/// connectives with their JS operator forms. `imp`/`iff`/`xor` are kept as
/// function calls (defined in the generated program).
fn translate_logic_words(formula: &str) -> String {
    let unicode = formula
        .replace('∧', " && ")
        .replace('¬', " ! ")
        .replace('∨', " || ")
        .replace('~', " ! ");

    let mut out = String::with_capacity(unicode.len());
    let bytes = unicode.as_bytes();
    let mut i = 0;
    while i < bytes.len() {
        let c = bytes[i] as char;
        if c.is_ascii_alphabetic() || c == '_' || c == '$' {
            let start = i;
            while i < bytes.len() {
                let d = bytes[i] as char;
                if d.is_ascii_alphanumeric() || d == '_' || d == '$' {
                    i += 1;
                } else {
                    break;
                }
            }
            match &unicode[start..i] {
                "and" => out.push_str("&&"),
                "or" => out.push_str("||"),
                "not" => out.push('!'),
                other => out.push_str(other),
            }
        } else {
            out.push(c);
            i += 1;
        }
    }
    out
}

/// Reserved identifiers in a logic program that are NOT boolean variables.
const LOGIC_RESERVED: &[&str] = &[
    "imp", "iff", "xor", "true", "false", "Math", "NaN", "Infinity",
];

/// Collect the distinct free identifiers of a (already word-translated) formula,
/// in first-seen order. These become the truth-table's boolean variables.
fn extract_logic_vars(formula: &str) -> Vec<String> {
    let mut vars: Vec<String> = Vec::new();
    let bytes = formula.as_bytes();
    let mut i = 0;
    while i < bytes.len() {
        let c = bytes[i] as char;
        if c.is_ascii_alphabetic() || c == '_' || c == '$' {
            let start = i;
            while i < bytes.len() {
                let d = bytes[i] as char;
                if d.is_ascii_alphanumeric() || d == '_' || d == '$' {
                    i += 1;
                } else {
                    break;
                }
            }
            let ident = &formula[start..i];
            // A function-call identifier (followed by `(`) is an operator, not a var.
            let is_call = formula[i..].trim_start().starts_with('(');
            if !LOGIC_RESERVED.contains(&ident) && !is_call && !vars.iter().any(|v| v == ident) {
                vars.push(ident.to_string());
            }
        } else {
            i += 1;
        }
    }
    vars
}

/// Decide a polynomial identity over ℤ via the sovereign ring solver
/// (`decideRingIdentityStr`, canonical-normal-form equality). Input is
/// `lhs = rhs`; supports `+ - * ^` and parentheses. Returns a verdict plus the
/// shared normal form when equal.
pub fn eval_ring(input: &str) -> Result<String> {
    let (lhs, rhs) = input
        .split_once('=')
        .ok_or_else(|| anyhow!("usage: ring <lhs> = <rhs>   e.g. ring (a+b)^2 = a^2+2*a*b+b^2"))?;
    let lhs = lhs.trim();
    let rhs = rhs.trim().trim_start_matches('=').trim(); // tolerate `==`
    if lhs.is_empty() || rhs.is_empty() {
        return Err(anyhow!("usage: ring <lhs> = <rhs>"));
    }
    let solver = aeon_logic_src("sovereign-ring.ts").ok_or_else(|| {
        anyhow!("could not locate open-source/aeon-logic/src/sovereign-ring.ts (set MOONSHINE_AEON_LOGIC)")
    })?;
    let program = format!(
        "import {{ decideRingIdentityStr }} from {import_path:?};\n\
         const r = decideRingIdentityStr({lhs:?}, {rhs:?});\n\
         const msg = r.equal ? (\"identity \\u2713  normal form: \" + r.nf)\n\
         \x20 : (\"not an identity  (lhs: \" + r.lhsNf + \"  |  rhs: \" + r.rhsNf + \")\");\n\
         console.log({sentinel:?} + msg);\n",
        import_path = solver.to_string_lossy(),
        sentinel = GNODE_SENTINEL,
    );
    let value = run_via_gnode(&program)?;
    if value.is_empty() {
        Err(anyhow!("ring solver returned no verdict (check the expression)"))
    } else {
        Ok(value)
    }
}

/// Decide integer-linear feasibility via the sovereign Omega test
/// (`solveOmega`, Pugh 1991). Input is a comma/`and`-separated conjunction of
/// linear constraints over integer variables, e.g. `2x+3y>=6, x-y=1, x>=0`.
/// Returns SAT (with a witness) or UNSAT.
pub fn eval_omega(input: &str) -> Result<String> {
    let system = parse_linear_system(input)?;
    let solver = aeon_logic_src("sovereign-omega.ts").ok_or_else(|| {
        anyhow!("could not locate open-source/aeon-logic/src/sovereign-omega.ts (set MOONSHINE_AEON_LOGIC)")
    })?;
    let program = format!(
        "import {{ solveOmega }} from {import_path:?};\n\
         const system = {system_js};\n\
         const names = {names_js};\n\
         const r = solveOmega(system);\n\
         let msg;\n\
         if (r.status === 'sat') {{\n\
         \x20 msg = 'satisfiable: ' + r.witness.map((v, i) => names[i] + ' = ' + v.toString()).join(', ');\n\
         }} else if (r.status === 'unsat') {{ msg = 'unsatisfiable (no integer solution)'; }}\n\
         else {{ msg = 'unknown: ' + r.reason; }}\n\
         console.log({sentinel:?} + msg);\n",
        import_path = solver.to_string_lossy(),
        system_js = system.0,
        names_js = system.1,
        sentinel = GNODE_SENTINEL,
    );
    let value = run_via_gnode(&program)?;
    if value.is_empty() {
        Err(anyhow!("omega solver returned no result"))
    } else {
        Ok(value)
    }
}

/// Parse a conjunction of linear constraints into `(LinearSystem JS literal,
/// variable-names JS array)`. Variables are ordered by first appearance.
/// Strict `<`/`>` are tightened to `<=`/`>=` over ℤ (a>b ⟺ a>=b+1).
fn parse_linear_system(input: &str) -> Result<(String, String)> {
    let pieces: Vec<&str> = input
        .split([',', ';', '\n'])
        .flat_map(|p| p.split(" and "))
        .map(|p| p.trim())
        .filter(|p| !p.is_empty())
        .collect();
    if pieces.is_empty() {
        return Err(anyhow!("usage: omega <constraint>[, <constraint> ...]  e.g. omega 2x+3y>=6, x-y=1"));
    }
    let mut order: Vec<char> = Vec::new();
    let mut rows: Vec<LinearConstraint> = Vec::new();
    for p in &pieces {
        let (coeffs, constant, relation) = parse_constraint(p)
            .ok_or_else(|| anyhow!("could not parse linear constraint: `{p}` (linear, integer coefficients only)"))?;
        for (v, _) in &coeffs {
            if !order.contains(v) {
                order.push(*v);
            }
        }
        rows.push((coeffs, constant, relation));
    }
    let n = order.len();
    let mut constraints_js = String::from("[");
    for (coeffs, constant, relation) in &rows {
        let mut vec = vec![0i64; n];
        for (v, c) in coeffs {
            let idx = order.iter().position(|x| x == v).unwrap();
            vec[idx] = *c;
        }
        let coeffs_js = vec
            .iter()
            .map(|c| format!("{c}n"))
            .collect::<Vec<_>>()
            .join(", ");
        constraints_js.push_str(&format!(
            "{{ coeffs: [{coeffs_js}], constant: {constant}n, relation: '{relation}' }}, "
        ));
    }
    constraints_js.push(']');
    let system_js = format!("{{ numVars: {n}, constraints: {constraints_js} }}");
    let names_js = format!(
        "[{}]",
        order
            .iter()
            .map(|v| format!("'{v}'"))
            .collect::<Vec<_>>()
            .join(", ")
    );
    Ok((system_js, names_js))
}

/// Parse one constraint `lhs <rel> rhs` into normalized `Σcᵢvᵢ + k {≥0|=0}` form
/// (`relation` is `"ge"` or `"eq"`); strict inequalities are integer-tightened.
type LinearConstraint = (Vec<(char, i64)>, i64, &'static str);

fn parse_constraint(s: &str) -> Option<LinearConstraint> {
    let (split_at, oplen, kind) = ["<=", ">=", "==", "=", "<", ">"]
        .iter()
        .find_map(|op| s.find(op).map(|i| (i, op.len(), *op)))?;
    let lhs = &s[..split_at];
    let rhs = &s[split_at + oplen..];
    let (lc, lk) = parse_linear_side(lhs)?;
    let (rc, rk) = parse_linear_side(rhs)?;
    // Move to lhs - rhs, forming `expr {rel} 0`.
    let mut coeffs: Vec<(char, i64)> = Vec::new();
    let mut add = |v: char, c: i64| {
        if let Some(e) = coeffs.iter_mut().find(|(x, _)| *x == v) {
            e.1 += c;
        } else {
            coeffs.push((v, c));
        }
    };
    for (v, c) in lc {
        add(v, c);
    }
    for (v, c) in rc {
        add(v, -c);
    }
    let mut constant = lk - rk;
    // Orient so the relation is `expr >= 0` (ge) or `expr == 0` (eq).
    let (flip, tighten, relation) = match kind {
        "=" | "==" => (false, 0, "eq"),
        ">=" => (false, 0, "ge"),
        ">" => (false, -1, "ge"),  // expr > 0  ⟺ expr - 1 >= 0
        "<=" => (true, 0, "ge"),   // expr <= 0 ⟺ -expr >= 0
        "<" => (true, -1, "ge"),   // expr < 0  ⟺ -expr - 1 >= 0
        _ => return None,
    };
    if flip {
        for e in coeffs.iter_mut() {
            e.1 = -e.1;
        }
        constant = -constant;
    }
    constant += tighten;
    coeffs.retain(|(_, c)| *c != 0);
    Some((coeffs, constant, relation))
}

/// Parse one side of a constraint: a sum of signed `coeff·var` terms and integer
/// constants. Returns the per-variable coefficients and the constant. Rejects
/// anything nonlinear (a variable adjacent to `^`, `*`, or another letter).
fn parse_linear_side(s: &str) -> Option<(Vec<(char, i64)>, i64)> {
    let compact: String = s.chars().filter(|c| !c.is_whitespace()).collect();
    if compact.is_empty() {
        return None;
    }
    let compact = if compact.starts_with(['+', '-']) {
        compact
    } else {
        format!("+{compact}")
    };
    let chars: Vec<char> = compact.chars().collect();
    let mut coeffs: Vec<(char, i64)> = Vec::new();
    let mut constant = 0i64;
    let mut i = 0;
    while i < chars.len() {
        let sign = match chars[i] {
            '+' => 1i64,
            '-' => -1i64,
            _ => return None,
        };
        i += 1;
        let start = i;
        while i < chars.len() && chars[i].is_ascii_digit() {
            i += 1;
        }
        let num: String = chars[start..i].iter().collect();
        if i < chars.len() && chars[i].is_ascii_alphabetic() {
            let var = chars[i];
            i += 1;
            // Reject nonlinear: a letter followed by `^`, another letter, or `*`.
            if i < chars.len() && matches!(chars[i], '^' | '*') {
                return None;
            }
            if i < chars.len() && chars[i].is_ascii_alphabetic() {
                return None;
            }
            let coeff = if num.is_empty() { 1 } else { num.parse().ok()? };
            if let Some(e) = coeffs.iter_mut().find(|(x, _)| *x == var) {
                e.1 += sign * coeff;
            } else {
                coeffs.push((var, sign * coeff));
            }
        } else {
            if num.is_empty() {
                return None;
            }
            constant += sign * num.parse::<i64>().ok()?;
        }
    }
    Some((coeffs, constant))
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn detects_plain_arithmetic() {
        assert_eq!(detect_arithmetic("1+2").as_deref(), Some("1+2"));
        assert_eq!(detect_arithmetic("1+2=").as_deref(), Some("1+2"));
        assert_eq!(
            detect_arithmetic("(1+2)*3 == 9").as_deref(),
            Some("(1+2)*3 == 9")
        );
        assert_eq!(detect_arithmetic("2^3").as_deref(), Some("2**3"));
        assert_eq!(
            detect_arithmetic("Math.sqrt(16) + 1").as_deref(),
            Some("Math.sqrt(16) + 1")
        );
    }

    #[test]
    fn rejects_commands_and_bare_values() {
        // No operator -> not a calculation.
        assert_eq!(detect_arithmetic("5"), None);
        assert_eq!(detect_arithmetic("(5)"), None);
        // Real commands must pass through untouched.
        assert_eq!(detect_arithmetic("ls -la"), None);
        assert_eq!(detect_arithmetic("git log"), None);
        assert_eq!(detect_arithmetic("echo 1+2"), None);
        assert_eq!(detect_arithmetic("./build.sh"), None);
        assert_eq!(detect_arithmetic("x=5"), None);
    }

    #[test]
    fn logic_vars_skip_functions_and_reserved() {
        let f = translate_logic_words("imp(a, b) and not c");
        assert_eq!(f, "imp(a, b) && ! c");
        assert_eq!(extract_logic_vars(&f), vec!["a", "b", "c"]);
    }
}
